1	import { defineStore } from 'pinia'
2	import { ref } from 'vue'
3	import { sessionsApi } from '@/api/endpoints/sessions'
4	
5	export interface Session {
6	  id: string
7	  course_id: string
8	  course_title: string
9	  instructor_id: string
10	  instructor_name: string
11	  room_id: string
12	  room_name: string
13	  location_id: string
14	  location_name: string
15	  start_time: string
16	  end_time: string
17	  capacity: number
18	  enrolled_count: number
19	  buffer_minutes: number
20	  status: 'scheduled' | 'live' | 'completed' | 'cancelled'
21	  recurrence_rule_id: string | null
22	  created_by: string
23	  created_at: string
24	}
25	
26	export const useSessionsStore = defineStore('sessions', () => {
27	  const weekSessions = ref<Session[]>([])
28	  const monthlySessions = ref<Session[]>([])
29	  const currentSession = ref<Session | null>(null)
30	  const roster = ref<any[]>([])
31	  const loading = ref(false)
32	
33	  async function fetchWeek(week: string, tz: string, locationId?: string) {
34	    loading.value = true
35	    try {
36	      weekSessions.value = await sessionsApi.getWeek(week, tz, locationId)
37	    } finally {
38	      loading.value = false
39	    }
40	  }
41	
42	  async function fetchMonth(month: string, tz: string) {
43	    loading.value = true
44	    try {
45	      monthlySessions.value = await sessionsApi.getMonth(month, tz)
46	    } finally {
47	      loading.value = false
48	    }
49	  }
50	
51	  async function fetchOne(id: string) {
52	    loading.value = true
53	    try {
54	      currentSession.value = await sessionsApi.getOne(id)
55	    } finally {
56	      loading.value = false
57	    }
58	  }
59	
60	  async function create(payload: Partial<Session>) {
61	    return await sessionsApi.create(payload)
62	  }
63	
64	  async function createRecurring(payload: object) {
65	    return await sessionsApi.createRecurring(payload)
66	  }
67	
68	  async function update(id: string, payload: Partial<Session>) {
69	    const updated = await sessionsApi.update(id, payload)
70	    if (currentSession.value?.id === id) currentSession.value = updated
71	    return updated
72	  }
73	
74	  async function cancel(id: string) {
75	    const updated = await sessionsApi.cancel(id)
76	    if (currentSession.value?.id === id) currentSession.value = updated
77	    return updated
78	  }
79	
80	  async function goLive(id: string) {
81	    const updated = await sessionsApi.goLive(id)
82	    if (currentSession.value?.id === id) currentSession.value = updated
83	    return updated
84	  }
85	
86	  async function complete(id: string) {
87	    const updated = await sessionsApi.complete(id)
88	    if (currentSession.value?.id === id) currentSession.value = updated
89	    return updated
90	  }
91	
92	  async function fetchRoster(id: string) {
93	    roster.value = await sessionsApi.getRoster(id)
94	    return roster.value
95	  }
96	
97	  return {
98	    weekSessions, monthlySessions, currentSession, roster, loading,
99	    fetchWeek, fetchMonth, fetchOne, create, createRecurring,
100	    update, cancel, goLive, complete, fetchRoster,
101	  }
102	})
103	

