 1	import { ref, onUnmounted } from 'vue'
 2	import { useAuthStore } from '@/stores/auth'
 3	
 4	export interface RoomState {
 5	  session_status: string
 6	  enrolled_count: number
 7	  checked_in_count: number
 8	}
 9	
10	export interface RoomEvent {
11	  type: string
12	  payload: Record<string, unknown>
13	  timestamp: Date
14	}
15	
16	export function useWebSocket(sessionId: string) {
17	  const auth = useAuthStore()
18	  const roomState = ref<RoomState | null>(null)
19	  const events = ref<RoomEvent[]>([])
20	  const connectionStatus = ref<'connecting' | 'connected' | 'disconnected' | 'error'>('connecting')
21	
22	  let ws: WebSocket | null = null
23	  let retryDelay = 1000
24	  let retryTimeout: ReturnType<typeof setTimeout> | null = null
25	  let destroyed = false
26	
27	  function connect() {
28	    if (destroyed) return
29	    const token = auth.accessToken
30	    if (!token) { connectionStatus.value = 'error'; return }
31	
32	    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
33	    const url = `${protocol}//${window.location.host}/api/ws/sessions/${sessionId}/room?token=${token}`
34	
35	    ws = new WebSocket(url)
36	    connectionStatus.value = 'connecting'
37	
38	    ws.onopen = () => {
39	      connectionStatus.value = 'connected'
40	      retryDelay = 1000
41	    }
42	
43	    ws.onmessage = (evt) => {
44	      let msg: Record<string, unknown>
45	      try { msg = JSON.parse(evt.data) } catch { return }
46	
47	      const type = msg.type as string
48	      events.value.unshift({ type, payload: msg, timestamp: new Date() })
49	      // Keep last 100 events
50	      if (events.value.length > 100) events.value = events.value.slice(0, 100)
51	
52	      if (type === 'room_state') {
53	        roomState.value = {
54	          session_status: msg.session_status as string,
55	          enrolled_count: msg.enrolled_count as number,
56	          checked_in_count: msg.checked_in_count as number,
57	        }
58	      } else if (type === 'session_status_changed') {
59	        if (roomState.value) roomState.value.session_status = msg.status as string
60	      } else if (type === 'attendee_joined') {
61	        if (roomState.value) roomState.value.checked_in_count++
62	      } else if (type === 'attendee_left') {
63	        if (roomState.value && roomState.value.checked_in_count > 0) roomState.value.checked_in_count--
64	      } else if (type === 'roster_update') {
65	        if (roomState.value) roomState.value.enrolled_count = msg.enrolled_count as number
66	      }
67	    }
68	
69	    ws.onerror = () => { connectionStatus.value = 'error' }
70	
71	    ws.onclose = (evt) => {
72	      connectionStatus.value = 'disconnected'
73	      if (!destroyed && evt.code !== 1000) {
74	        // Exponential backoff, max 30s
75	        retryTimeout = setTimeout(() => { retryDelay = Math.min(retryDelay * 2, 30000); connect() }, retryDelay)
76	      }
77	    }
78	  }
79	
80	  function disconnect() {
81	    destroyed = true
82	    if (retryTimeout) clearTimeout(retryTimeout)
83	    ws?.close(1000, 'component unmounted')
84	  }
85	
86	  connect()
87	  onUnmounted(disconnect)
88	
89	  return { roomState, events, connectionStatus, disconnect }
90	}

