watch(events, async (evts) => {
  const latest = evts[0]
  if (!latest) return
  const msg = latest.payload as any

  if (msg.type === 'webrtc_offer' && !isInstructor.value) {
    // Learner receives offer from instructor → send answer
    peerConnection = createPeerConnection()
    await peerConnection.setRemoteDescription(new RTCSessionDescription(msg.sdp))
    const answer = await peerConnection.createAnswer()
    await peerConnection.setLocalDescription(answer)
    sendWs({ type: 'webrtc_answer', sdp: answer })
  } else if (msg.type === 'webrtc_answer' && isInstructor.value) {
    await peerConnection?.setRemoteDescription(new RTCSessionDescription(msg.sdp))
  } else if (msg.type === 'webrtc_ice') {
    try { await peerConnection?.addIceCandidate(new RTCIceCandidate(msg.candidate)) } catch {}
  }
}, { deep: false })

