async function getOrCreateLocalStream() {
  if (!localStream) localStream = new MediaStream()
  return localStream
}

async function toggleMic() {
  if (micOn.value) {
    localStream?.getAudioTracks().forEach(t => { t.stop(); localStream?.removeTrack(t) })
    micOn.value = false
  } else {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ audio: true })
      s.getAudioTracks().forEach(t => localStream?.addTrack(t))
      micOn.value = true
      await startOrUpdateBroadcast()
    } catch (e) { console.error('Mic error', e) }
  }
  updateLocalVideoEl()
}

async function toggleCam() {
  if (camOn.value) {
    localStream?.getVideoTracks().filter(t => t.label !== 'screen').forEach(t => { t.stop(); localStream?.removeTrack(t) })
    camOn.value = false
  } else {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: true })
      s.getVideoTracks().forEach(t => localStream?.addTrack(t))
      camOn.value = true
      await startOrUpdateBroadcast()
    } catch (e) { console.error('Cam error', e) }
  }
  updateLocalVideoEl()
}

async function toggleScreen() {
  if (screenSharing.value) {
    screenStream?.getTracks().forEach(t => t.stop())
    screenStream = null
    screenSharing.value = false
  } else {
    try {
      screenStream = await navigator.mediaDevices.getDisplayMedia({ video: true, audio: true })
      screenStream.getTracks().forEach(t => {
        localStream?.addTrack(t)
        t.onended = () => { screenSharing.value = false }
      })
      screenSharing.value = true
      await startOrUpdateBroadcast()
    } catch (e) { console.error('Screen share error', e) }
  }
  updateLocalVideoEl()
}

function updateLocalVideoEl() {
  if (localVideo.value) {
    localVideo.value.srcObject = localStream && localStream.getTracks().length > 0 ? localStream : null
  }
}

async function startOrUpdateBroadcast() {
  if (!localStream || localStream.getTracks().length === 0) return

  if (!peerConnection) peerConnection = createPeerConnection()

  // Replace tracks on existing senders or add new ones
  const senders = peerConnection.getSenders()
  for (const track of localStream.getTracks()) {
    const sender = senders.find(s => s.track?.kind === track.kind)
    if (sender) {
