    recording.value = true
  }
}

// ── Cleanup ───────────────────────────────────────────────────────────────────
onUnmounted(() => {
  localStream?.getTracks().forEach(t => t.stop())
  screenStream?.getTracks().forEach(t => t.stop())
  mediaRecorder?.stop()
  peerConnection?.close()
})
</script>

