function toggleRecording() {
  if (recording.value) {
    mediaRecorder?.stop()
    recording.value = false
    return
  }

  const tracks = localStream.getTracks()
  if (tracks.length === 0) {
    alert('Turn on your camera or screen share first, then start recording.')
    return
  }

  recordedChunks = []
  uploadState.uploading = false
  uploadState.done = false
  uploadState.error = ''

  const mimeType = getSupportedMimeType()
  mediaRecorder = new MediaRecorder(localStream, { mimeType })
  mediaRecorder.ondataavailable = (e) => { if (e.data.size > 0) recordedChunks.push(e.data) }
  mediaRecorder.onstop = () => uploadRecording(mimeType)
  mediaRecorder.start(1000)
  recording.value = true
}

async function uploadRecording(mimeType: string) {
  uploadState.uploading = true
  uploadState.error = ''
  try {
    const blob = new Blob(recordedChunks, { type: mimeType || 'video/webm' })
    const durationSeconds = Math.round(blob.size / 50000) // rough estimate

    // Step 1: Get presigned PUT URL from backend
    const { presigned_url } = await sessionsApi.initiateRecordingUpload(props.session.id)

    // Step 2: PUT blob directly to MinIO (bypass auth headers — presigned URL is self-contained)
    const uploadRes = await fetch(presigned_url, {
      method: 'PUT',
      body: blob,
      headers: { 'Content-Type': mimeType || 'video/webm' },
    })
    if (!uploadRes.ok) throw new Error(`Upload failed: ${uploadRes.status}`)

    // Step 3: Confirm upload with backend
    await sessionsApi.confirmRecordingUpload(props.session.id, blob.size, durationSeconds)
    uploadState.done = true
  } catch (err: any) {
    uploadState.error = err.message ?? 'Upload failed'
  } finally {
    uploadState.uploading = false
  }
}

function getSupportedMimeType(): string {
  const types = ['video/webm;codecs=vp9,opus', 'video/webm;codecs=vp8,opus', 'video/webm']
  return types.find(t => MediaRecorder.isTypeSupported(t)) ?? ''
}"}

