// Called when instructor starts/changes their stream — offer/re-offer to all known learners
async function broadcastStream() {
  if (!isInstructor.value || localStream.getTracks().length === 0) return
  for (const learnerId of knownLearnerIds) {
    const existing = peerConnections.get(learnerId)
    if (existing) {
      // Already connected — replace tracks in-place (avoids renegotiation teardown)
      const senders = existing.getSenders()
      for (const track of localStream.getTracks()) {
        const sender = senders.find(s => s.track?.kind === track.kind)
        if (sender) {
          await sender.replaceTrack(track)
        } else {
          existing.addTrack(track, localStream)
        }
      }
      const offer = await existing.createOffer()
      await existing.setLocalDescription(offer)
      sendWs({ type: 'webrtc_offer', sdp: offer, target_user_id: learnerId })
    } else {
      // First time streaming to this learner — create fresh peer connection
      await offerToLearner(learnerId)
    }
  }
}"}

