1	import { ref, onUnmounted } from 'vue'
2	import { useAuthStore } from '@/stores/auth'
3	
4	export interface RoomState {
5	  session_status: string
6	  enrolled_count: number
7	  checked_in_count: number
8	}
9	
10	export interface RoomEvent {
11	  type: string
12	  payload: Record<string, unknown>
13	  timestamp: Date
14	}
15	
16	export function useWebSocket(sessionId: string) {
17	  const auth = useAuthStore()
18	  const roomState = ref<RoomState | null>(null)
19	  const events = ref<RoomEvent[]>([])
20	  const connectionStatus = ref<'connecting' | 'connected' | 'disconnected' | 'error'>('connecting')
21	
22	  const wsRef = ref<WebSocket | null>(null)
23	  let ws: WebSocket | null = null
24	  let retryDelay = 1000
25	  let retryTimeout: ReturnType<typeof setTimeout> | null = null
26	  let destroyed = false
27	
28	  function connect() {
29	    if (destroyed) return
30	    const token = auth.accessToken
31	    if (!token) { connectionStatus.value = 'error'; return }
32	
33	    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
34	    const url = `${protocol}//${window.location.host}/api/ws/sessions/${sessionId}/room?token=${token}`
35	
36	    ws = new WebSocket(url)
37	    wsRef.value = ws
38	    connectionStatus.value = 'connecting'
39	
40	    ws.onopen = () => {
41	      connectionStatus.value = 'connected'
42	      retryDelay = 1000
43	    }
44	
45	    ws.onmessage = (evt) => {
46	      let msg: Record<string, unknown>
47	      try { msg = JSON.parse(evt.data) } catch { return }
48	
49	      const type = msg.type as string
50	      events.value.unshift({ type, payload: msg, timestamp: new Date() })
51	      // Keep last 100 events
52	      if (events.value.length > 100) events.value = events.value.slice(0, 100)
53	
54	      if (type === 'room_state') {
55	        roomState.value = {
56	          session_status: msg.session_status as string,
57	          enrolled_count: msg.enrolled_count as number,
58	          checked_in_count: msg.checked_in_count as number,
59	        }
60	      } else if (type === 'session_status_changed') {
61	        if (roomState.value) roomState.value.session_status = msg.status as string
62	      } else if (type === 'attendee_joined') {
63	        if (roomState.value) roomState.value.checked_in_count++
64	      } else if (type === 'attendee_left') {
65	        if (roomState.value && roomState.value.checked_in_count > 0) roomState.value.checked_in_count--
66	      } else if (type === 'roster_update') {
67	        if (roomState.value) roomState.value.enrolled_count = msg.enrolled_count as number
68	      }
69	    }
70	
71	    ws.onerror = () => { connectionStatus.value = 'error' }
72	
73	    ws.onclose = (evt) => {
74	      connectionStatus.value = 'disconnected'
75	      if (!destroyed && evt.code !== 1000) {
76	        // Exponential backoff, max 30s
77	        retryTimeout = setTimeout(() => { retryDelay = Math.min(retryDelay * 2, 30000); connect() }, retryDelay)
78	      }
79	    }
80	  }
81	
82	  function disconnect() {
83	    destroyed = true
84	    if (retryTimeout) clearTimeout(retryTimeout)
85	    ws?.close(1000, 'component unmounted')
86	  }
87	
88	  connect()
89	  onUnmounted(disconnect)
90	
91	  return { roomState, events, connectionStatus, disconnect, ws: wsRef }
92	}
93	

